import {RegistryClient} from 'jibo-client-framework';
import url from 'url';

function getRegistry(cb){
    let registryHost;
    let ipc = null;
    try {
        ipc = require('ipc');
    }
    catch(e){
        cb(e);
        return;
    }

    ipc.on('set-context', (initData) => {
        if(typeof initData === 'string' || initData instanceof String) {
            registryHost = initData;
        }
        else {
            registryHost = initData.registryHost;

            // The session token isn't used right now, so I'm just commenting this out
            /*if(initData.token) {
                this.session.token = initData.token;
                console.warn('Session Token = ' + this.session.token);
            }*/
        }

        const registryInfo = url.parse(registryHost);
        console.log('registryInfo');
        console.log(registryInfo);

        RegistryClient.createInstance(registryInfo.hostname, registryInfo.port);

        RegistryClient.instance.getRecords(cb);
    });

    ipc.send('get-context');
}

export default getRegistry;
